// Extraer User ID y validar contra lista de administradores
const input = $input.first().json;
const adminIds = [1320251824];
let userId, chatId, text, isCallback, queryId, messageId;

if (input.callback_query) {
  isCallback = true;
  userId = input.callback_query.from.id;
  chatId = input.callback_query.message.chat.id;
  text = input.callback_query.data;
  queryId = input.callback_query.id;
  messageId = input.callback_query.message.message_id;
} else if (input.message) {
  isCallback = false;
  userId = input.message.from.id;
  chatId = input.message.chat.id;
  text = input.message.text;
}

const admin = adminIds.includes(userId);

return [
  {
    "json": {
      isAdmin: admin,
      isCallback: isCallback,
      chatId: chatId,
      text: text,
      userId: userId,
      queryId: queryId,
      messageId: messageId
    }
  }
];

const parts = $json.text.split(':');
const action = parts[0];
const chatId = $json.chatId;
const queryId = $json.queryId;
const messageId = $json.messageId;

if (action === 'paginate') {
  const type = parts[1];
  const page = parseInt(parts[2]);
  // Pass through — downstream GS nodes will fetch fresh data
  // BuildPagCB will use $items('Manejar Callback') to get queryId/chatId/messageId/page
  const r2 = {queryId, chatId, messageId, action: 'paginate', type, page};
  return [{json: r2}];
}

if (action === 'noop') {
  const r = {queryId: queryId, chatId: chatId, messageId: messageId, action: 'noop'};
  return [{json: r}];
}

if (action === 'confirm') {
  const respuesta = parts[1];
  const r3 = {queryId: queryId, chatId: chatId, messageId: messageId, action: 'confirm', respuesta: respuesta};
  return [{json: r3}];
}

const r4 = {queryId: queryId, chatId: chatId, messageId: messageId, action: 'unknown'};
return [{json: r4}];

var chatId = 0;
try { chatId = $items('Validar Admin')[0].json.chatId; } catch(e) {}

var output = $input.first().json.output || '';

// escapar underscores para Telegram (evita error parse_mode)
output = output.replace(/_/g, '\\_');

// buscar marcador PAGINATED:Tipo:pag/total
var match = output.match(/^PAGINATED:(\w+):(\d+)\/(\d+)/m);
if (match) {
  var tipo = match[1];
  var currentPage = parseInt(match[2]);
  var totalPages = parseInt(match[3]);
  output = output.replace(/^PAGINATED:\w+:\d+\/\d+\n*/m, '');
  var prevBtnData = currentPage > 1 ? 'paginate:' + tipo + ':' + (currentPage - 1) : 'noop';
  var nextBtnData = currentPage < totalPages ? 'paginate:' + tipo + ':' + (currentPage + 1) : 'noop';
  return [{json: {output: output, chatId: chatId, isPaginated: true, prevBtnData: prevBtnData, nextBtnData: nextBtnData, currentPage: currentPage, totalPages: totalPages}}];
} else {
  return [{json: {output: output, chatId: chatId, isPaginated: false}}];
}

const mcItems = $items('Manejar Callback');
const mc = mcItems[0].json;
const queryId = mc.queryId;
const chatId = mc.chatId;
const messageId = mc.messageId;
const page = mc.page || 1;
const type = mc.type || '';

// GS devuelve UN ITEM POR FILA, no un array en un solo item
const allItems = $input.all();
let dataArray = [];

if (allItems.length > 0) {
  const first = allItems[0].json;
  if (Array.isArray(first)) {
    dataArray = first;
  } else if (first.results && Array.isArray(first.results)) {
    dataArray = first.results;
  } else if (first.data && Array.isArray(first.data)) {
    dataArray = first.data;
  } else {
    // Normal: cada item del input es una fila
    dataArray = allItems.map(i => i.json);
  }
}

const pageSize = 4;
const totalPages = Math.ceil(dataArray.length / pageSize);
const start = (page - 1) * pageSize;
const pageItems = dataArray.slice(start, start + pageSize);

var title = '';
if (type === 'Clientes') title = 'Clientes';
else if (type === 'Stock') title = 'Stock';
else if (type === 'Turnos') title = 'Turnos';
var text = title + '\n';
text += 'Página ' + page + ' de ' + totalPages + '\n\n';
for (let i = 0; i < pageItems.length; i++) {
  const item = pageItems[i];
  const num = start + i + 1;
  if (type === 'Clientes') {
    text += num + '. ' + (item['Nombre y Apellido'] || '-') + '\n';
    text += 'DNI: ' + (item['DNI'] != null ? item['DNI'] : '-') + '\n';
    text += 'Tel: ' + (item['Número De Teléfono'] != null ? item['Número De Teléfono'] : '-') + '\n';
    text += 'Dirección: ' + (item['Dirección'] || '-') + '\n';
  } else if (type === 'Stock') {
    text += num + '. ' + (item['Repuesto'] || '-') + '\n';
    text += 'Código: ' + (item['Código'] || '-') + '\n';
    text += 'Precio: \u0024' + (item['Precio Unitario'] != null ? item['Precio Unitario'] : '-') + '\n';
    text += 'Stock: ' + (item['Stock Actual'] != null ? item['Stock Actual'] : '-') + '\n';
  } else if (type === 'Turnos') {
    text += num + '. ' + (item['Auto'] || item['Nombre y Apellido'] || '-') + '\n';
    text += 'Motivo: ' + (item['Motivo'] || '-') + '\n';
    text += 'Fecha: ' + (item['Fecha del Turno'] || '-') + '\n';
    text += 'Horario: ' + (item['Horario'] || '-') + '\n';
    text += 'Estado: ' + (item['Estado'] || '-') + '\n';
  } else {
    text += num + '. ';
    const fields = Object.keys(item).filter(k => k !== 'row_number');
    for (let k = 0; k < fields.length; k++) {
      text += (item[fields[k]] || '-') + '\n';
    }
  }
  text += '\n';
}
text += '\u00bfQuer\u00e9s avanzar a la siguiente p\u00e1gina o volver a la anterior?';

const prevBtnData = (totalPages > 1 && page > 1) ? 'paginate:' + type + ':' + (page - 1) : 'noop';
const nextBtnData = (totalPages > 1 && page < totalPages) ? 'paginate:' + type + ':' + (page + 1) : 'noop';

const r = {pageText: text, chatId, messageId, queryId, prevBtnData, nextBtnData, currentPage: page, totalPages};
return [{json: r}];
